package com.amdox.nexushr;
import jakarta.persistence.*; import java.time.LocalDate;
@Entity @Table(name="leave_requests") public class LeaveRequest { @Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id; @ManyToOne(optional=false) private Employee employee; private String type; private LocalDate startDate; private LocalDate endDate; private String status; private String reason; protected LeaveRequest(){} public LeaveRequest(Employee e,String t,LocalDate s,LocalDate end,String st,String r){employee=e;type=t;startDate=s;endDate=end;status=st;reason=r;} public Long getId(){return id;} public Employee getEmployee(){return employee;} public String getType(){return type;} public LocalDate getStartDate(){return startDate;} public LocalDate getEndDate(){return endDate;} public String getStatus(){return status;} public void setStatus(String s){status=s;} public String getReason(){return reason;} }
